    bind = op.get_bind()
    inspector = sa.inspect(bind)
    if inspector.has_table("mp_performance"):
        mp_cols = {c["name"] for c in inspector.get_columns("mp_performance")}
        if "is_former_pm" not in mp_cols:
            op.add_column(
                "mp_performance",
                sa.Column("is_former_pm", sa.Boolean(), server_default=sa.text("false"), nullable=True),
            )
        if "pm_terms" not in mp_cols:
            op.add_column(
                "mp_performance",
                sa.Column("pm_terms", sa.Integer(), server_default=sa.text("0"), nullable=True),
            )
        op.execute("UPDATE mp_performance SET is_former_pm = false WHERE is_former_pm IS NULL")
        op.execute("UPDATE mp_performance SET pm_terms = 0 WHERE pm_terms IS NULL")

